CREATE TABLE "tax_decisions" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"canonical_operation_id" uuid NOT NULL REFERENCES "canonical_operations"("id"),"rule_id" text,"rule_version" text,"status" text NOT NULL,"tax_base" numeric(20,6),"tax_rate" numeric(10,6),"tax_amount" numeric(20,6),"total_amount" numeric(20,6),"explanation" jsonb NOT NULL,"decided_at" timestamptz NOT NULL DEFAULT now());
CREATE TABLE "fiscal_documents" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"canonical_operation_id" uuid NOT NULL REFERENCES "canonical_operations"("id"),"number" text NOT NULL,"document_type" text NOT NULL,"status" text NOT NULL,"original_document_id" uuid,"issued_at" timestamptz NOT NULL,"tax_base" numeric(20,6) NOT NULL,"tax_amount" numeric(20,6) NOT NULL,"total_amount" numeric(20,6) NOT NULL,"currency" text NOT NULL,"render_storage_key" text NOT NULL,"render_sha256" text NOT NULL,"locked" boolean NOT NULL DEFAULT true);
ALTER TABLE "fiscal_documents" ADD CONSTRAINT "fiscal_documents_original_fk" FOREIGN KEY ("original_document_id") REFERENCES "fiscal_documents"("id");
CREATE UNIQUE INDEX "fiscal_document_number_uq" ON "fiscal_documents"("tenant_id","number");
